const iobNode = Object.values(flow.get('iobroker_in_nodes') || {})[0];
if (!iobNode) {
    node.warn('No iob-in node found');
    return null;
}

iobNode.triggerCached();
return null;

const iobNode = Object.values(flow.get('iobroker_in_nodes') || {}).find(n => n.supportsDynamicTopic);
if (!iobNode) {
    node.warn('No single-mode iob-in node found');
    return null;
}

(async () => {
    await iobNode.triggerWithTopic(msg.topic);
})();

return null;

// Get all registered iob-in nodes with external triggering enabled
const nodes = flow.get('iobroker_in_nodes') || {};

// Build overview
const nodeList = [];
for (const [nodeId, nodeInfo] of Object.entries(nodes)) {
    nodeList.push({
        id: nodeId.substring(0, 8) + '...',
        name: nodeInfo.name,
        mode: nodeInfo.mode,
        states: nodeInfo.states,
        currentState: nodeInfo.stateId,
        outputMode: nodeInfo.outputMode,
        supportsDynamicTopic: nodeInfo.supportsDynamicTopic || false,
        supportsDynamicArray: nodeInfo.supportsDynamicArray || false,
        group: nodeInfo.group
    });
}

if (nodeList.length === 0) {
    node.warn('No nodes registered for external triggering');
} else {
    node.status({ fill: 'green', shape: 'dot', text: `${nodeList.length} nodes found` });
}

msg.payload = nodeList;
msg.count = nodeList.length;
return msg;

const iobNode = Object.values(flow.get('iobroker_in_nodes') || {}).find(n => n.supportsDynamicArray);
if (!iobNode) {
    node.warn('No multiple-mode iob-in node found');
    return null;
}

(async () => {
    await iobNode.triggerWithTopicArray(msg.payload, msg.outputMode);
})();

return null;
